import { Dose, Appointment, Supply } from './types';

// Mock Dose History
export const doseHistory: Dose[] = Array.from({ length: 90 }, (_, i) => {
  const date = new Date();
  date.setDate(date.getDate() - (i + 1));
  const random = Math.random();
  let status: 'taken' | 'missed' | 'pending' = 'taken';
  if (random > 0.95) {
    status = 'missed';
  }
  return { date, status };
});

